const thread = $input.first().json;
const messages = thread.messages || [];
const last = messages[messages.length - 1] || {};
const headerVal = (msg, name) => {
  const h = (msg.payload && msg.payload.headers) || [];
  const found = h.find((x) => (x.name || '').toLowerCase() === name);
  return found ? found.value : (msg[name] || '');
};
const last_message_from = headerVal(last, 'from') || last.From || '';
const subject = headerVal(last, 'subject') || last.Subject || thread.snippet || '';

const truncated = messages.slice(-3).map((m) => ({
  from: headerVal(m, 'from') || m.From || '',
  body: ((m.snippet || m.textPlain || m.body || '') + '').slice(0, 2000),
}));

const source_inbox = "eganbonde@gmail.com";
return [{ json: {
  thread_id: thread.id,
  source_ref: source_inbox + ':' + thread.id,
  source_inbox,
  subject,
  last_message_from,
  messages: truncated,
} }];

const d = $json;
const action = {
  table: 'cos.pending_decisions',
  op: 'UPDATE',
  set: { status: 'done', resolved_at: 'now()' },
  where: { source: 'email', source_ref: d.source_ref, status: 'open' },
};
return [{ json: {
  source_ref: d.source_ref,
  parsed_action_json: JSON.stringify(action).replace(/'/g, "''"),
} }];

const d = $input.first().json;
return [{ json: {
  source_ref: d.source_ref,
  source_inbox: d.source_inbox,
  from: d.last_message_from,
  subject: d.subject,
  messages: d.messages,
} }];

